export default async function handler(req, res) {
  try {
  setCorsHeaders(req, res)

  if (req.method === 'OPTIONS') return res.status(200).end()
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' })

  // ── Rate limit: 30 share cards per user per day ───────────────────────────
  let rl;
  try {
    rl = await rateLimitCheck(req, { userDay: 30, ipDay: 60, prefix: 'share-card' });
  } catch (rlErr) {
    console.error('[share-card] rate limiter threw (failing open):', rlErr.message);
    rl = { allowed: true };
  }
  if (!rl.allowed) return res.status(429).json({ error: rl.reason })

  // ── Auth ──────────────────────────────────────────────────────────────────
  const authHeader = req.headers.authorization || ''
  const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : null
  if (!token) return res.status(401).json({ error: 'Authentication required' })

  let authResult;
  try {
    authResult = await supabaseAdmin.auth.getUser(token);
  } catch (err) {
    console.error('[share-card] auth.getUser threw:', err.message);
    return res.status(503).json({ error: 'Authentication service unavailable. Please try again.' });
  }
  const { data: { user }, error: authError } = authResult;
  if (authError || !user) return res.status(401).json({ error: 'Invalid or expired token' })

  // ── Fetch defense result (server reads the score — client cannot fake it) ─
  const { project_id, style } = req.body || {}
  if (!project_id) return res.status(400).json({ error: 'project_id required' })

  // style is cosmetic only — it never affects the score/topic/name below,
  // so a client sending a bogus value just falls back to the default look.
  const VALID_STYLES = ['dark', 'scoreboard', 'prestige']
  const safeStyle = VALID_STYLES.includes(style) ? style : 'dark'

  const { data: step, error: stepError } = await supabaseAdmin
    .from('project_steps')
    .select('result_json, user_id')
    .eq('project_id', project_id)
    .eq('step_type', 'defense_prep')
    .eq('user_id', user.id)   // ownership enforced here — not via RLS (we use service_role)
    .maybeSingle()

  if (stepError || !step) {
    return res.status(403).json({ error: 'Defense session not found or access denied' })
  }

  // Fetch project title for the card
  const { data: project } = await supabaseAdmin
    .from('projects')
    .select('title')
    .eq('id', project_id)
    .eq('user_id', user.id)
    .maybeSingle()

  const result = step.result_json || {}
  const score       = result.panel_score ?? null
  const scoreLabel  = result.panel_score_label ?? null
  const topic       = project?.title || result.topic || ''
  const studentName = user.user_metadata?.full_name || ''

  // ── Render PNG via @vercel/og ─────────────────────────────────────────────
  // Prestige has no raster logo (it uses an inline SVG shield instead), so
  // skip the network fetch entirely for that style.
  let logoBase64 = null
  if (safeStyle !== 'prestige') {
    try {
      const logoUrl = safeStyle === 'scoreboard'
        ? 'https://www.fypro.com.ng/fypro-logo-white.png'
        : 'https://www.fypro.com.ng/fypro-logo.png'
      const logoRes = await fetch(logoUrl)
      if (!logoRes.ok) throw new Error('logo fetch failed')
      const logoBuffer = await logoRes.arrayBuffer()
      const logoData = Buffer.from(logoBuffer).toString('base64')
      logoBase64 = `data:image/png;base64,${logoData}`
    } catch (_) {
      // logo fetch failed — card renders without it
    }
  }

  try {
    const cardElement =
      safeStyle === 'scoreboard' ? buildScoreboardCard(score, scoreLabel, topic, studentName, logoBase64) :
      safeStyle === 'prestige'   ? buildPrestigeCard(score, scoreLabel, topic, studentName) :
      buildDarkCard(score, scoreLabel, topic, studentName, logoBase64)

    const imgResponse = new ImageResponse(
      cardElement,
      { width: WIDTH, height: HEIGHT }
    )

    const arrayBuffer = await imgResponse.arrayBuffer()

    res.setHeader('Content-Type', 'image/png')
    res.setHeader('Cache-Control', 'private, no-store')
    res.setHeader('Content-Disposition', 'attachment; filename="fypro-defense-result.png"')
    return res.end(Buffer.from(arrayBuffer))
  } catch (err) {
    console.error('[share-card] render failed:', err.message)
    sendTelegramAlert(`🔴 Share card render failed — ${err.message}`).catch(() => null)
    return res.status(500).json({ error: 'Image generation failed' })
  }
  } catch (err) {
    Sentry.captureException(err)
    console.error('[api/share-card] unhandled error:', err)
    if (!res.headersSent) return res.status(500).json({ error: 'Internal server error' })
  }
}
